import React, { createContext, useState, useContext, useEffect } from 'react';

const ListingContext = createContext();

export const useListings = () => {
  return useContext(ListingContext);
};

export const ListingProvider = ({ children }) => {
  const [listings, setListings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulate fetching listings from backend
    const fetchListings = () => {
      // Mock data - in a real app, you would fetch from your backend
      const mockListings = [
        {
          id: 1,
          title: 'Canon EOS R5 Camera',
          description: 'Professional mirrorless camera with 45MP sensor',
          price_per_day: 45,
          category: 'Electronics',
          image: 'https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&w=400&h=300',
          owner: 'John D.',
          rating: 4.9
        },
        {
          id: 2,
          title: 'Mountain Bike',
          description: 'Full suspension mountain bike, perfect for trails',
          price_per_day: 25,
          category: 'Sports',
          image: 'https://images.unsplash.com/photo-1519817914152-22d216bb9170?auto=format&fit=crop&w=400&h=300',
          owner: 'Sarah M.',
          rating: 4.7
        },
        {
          id: 3,
          title: 'Power Drill Set',
          description: 'Cordless drill with multiple bits and attachments',
          price_per_day: 15,
          category: 'Tools',
          image: 'https://images.unsplash.com/photo-1519817914152-22d216bb9170?auto=format&fit=crop&w=400&h=300',
          owner: 'Mike T.',
          rating: 4.8
        },
        {
          id: 4,
          title: 'Designer Handbag',
          description: 'Genuine leather handbag from a premium brand',
          price_per_day: 35,
          category: 'Fashion',
          image: 'https://images.unsplash.com/photo-1519817914152-22d216bb9170?auto=format&fit=crop&w=400&h=300',
          owner: 'Emma L.',
          rating: 5.0
        }
      ];
      
      setListings(mockListings);
      setLoading(false);
    };

    setTimeout(() => {
      fetchListings();
    }, 1000); // Simulate network delay
  }, []);

  const addListing = (newListing) => {
    const listing = {
      ...newListing,
      id: Date.now(),
      image: "https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&w=400&h=300",
      owner: "You",
      rating: 5.0
    };
    setListings(prev => [...prev, listing]);
  };

  const updateListing = (id, updatedListing) => {
    setListings(prev => 
      prev.map(listing => 
        listing.id === id ? { ...listing, ...updatedListing } : listing
      )
    );
  };

  const deleteListing = (id) => {
    setListings(prev => prev.filter(listing => listing.id !== id));
  };

  const value = {
    listings,
    loading,
    addListing,
    updateListing,
    deleteListing
  };

  return (
    <ListingContext.Provider value={value}>
      {children}
    </ListingContext.Provider>
  );
};
